const html = $input.item.json.data;

const idMatch      = html.match(/nabidka\/(\d+)/);
const titleMatch   = html.match(/<title>(.*?) \|/i);
const companyMatch = html.match(/"hiringOrganization":\s?\{.*?"name":\s?"(.*?)"/i);
const logoMatch    = html.match(/"logo":\s?"(.*?)"/i);

const canonicalMatch = html.match(/link href="(https:\/\/www\.startupjobs\.cz\/nabidka\/.*?)"/i);
const companyUrl   = html.match(/"hiringOrganization":\s?\{.*?"url":\s?"(.*?)"/i);
const dateMatch    = html.match(/"datePosted":\s?"(.*?)"/i);

const jobId = idMatch ? idMatch[1] : null; 
const applyUrl = jobId ? `https://www.startupjobs.cz/nabidka/${jobId}/prihlasit#application` : null;

let cleanTitle = titleMatch ? titleMatch[1] : "Other";
cleanTitle = cleanTitle.replace(/&#x2F;/g, '/').replace(/&amp;/g, '&').trim();
let cleanLogo = logoMatch ? logoMatch[1] : "Other";
cleanLogo = cleanLogo.replace(/\\/g, '');
let cleanJobUrl = (canonicalMatch && canonicalMatch[1]) ? canonicalMatch[1].split('"')[0] : "Other";

return {
    jobId:       idMatch ? idMatch[1] : "Other",
    jobTitle:    cleanTitle,
    jobUrl:      cleanJobUrl,
    companyName: companyMatch ? companyMatch[1] : "Other",
    companyUrl:  companyUrl ? companyUrl[1] : "Other",
    companyLogo: cleanLogo,
    publishedAt: dateMatch ? dateMatch[1] : "Other",
    applyUrl:    applyUrl ? applyUrl : "Other"
};

const raw = $input.item.json.data;
const cleanHtml = raw.replace(/\\"/g, '"').replace(/\\n/g, '\n');

const match = cleanHtml.match(/<div class="output-content">(.*?)<\/div>/s);

if (!match) return { jobDescription: "Description section not found." };

let text = match[1];

text = text
    .replace(/<\/p>/g, '\n\n')       // Add double spacing after paragraphs
    .replace(/<\/div>/g, '\n')       // Single space for div blocks
    .replace(/<\/li>/g, '\n')         // Add a new line after list items
    .replace(/<li>/g, '• ')           // Add a bullet point symbol
    .replace(/<[^>]+>/g, '')          // Remove all other remaining HTML tags
    .replace(/&nbsp;/g, ' ')          // Fix non-breaking spaces
    .replace(/&amp;/g, '&')           // Fix ampersands
    .trim();                          // Remove extra space at start/end

return {
    jobDescription: text
};

const platformName = "startupjobscz";

for (const item of $input.all()) {
  item.json.source = platformName;
}

return $input.all();

const raw = JSON.stringify($input.item.json.data).toLowerCase();

const getInfo = (options, isLocation = false) => {
    let found = options.filter(opt => raw.includes(opt.toLowerCase()));
    found = found.map(word => word.replace(/_/g, ' '));
    if (isLocation && (found.includes("Praha") || found.includes("Prague"))) {
        return "Prague";
    }
    return found.length > 0 ? found.join(", ") : "Other";
};

const locationOptions = ["Praha", "Prague"]; 
const experienceLevelOptions = ["Junior", "Medior", "Senior"];
const contractOptions = ["Full-time", "Part-time"];
const employmentOptions = ["Freelance", "Work_Contract"];
const workModeOptions = ["Remote", "Hybrid", "On-site"];

return {
    workMode: getInfo(workModeOptions),
    location: getInfo(locationOptions, true),
    contractType: getInfo(contractOptions),
    employmentType: getInfo(employmentOptions),
    experienceLevel: getInfo(experienceLevelOptions)
};

